# Worked focus: http-py-http2-multiplexing — Model HTTP/2 streams, field compression, flow control, concurrency limits, and connection-level failure. Demonstrate the result through Python 3.14 urllib, http.client, ssl, typed protocols, and fixture transports.
def worked_http_py_connections_protocols_3(protocol: str, active_streams: int, stream_limit: int) -> dict[str, bool]:
    assert protocol in {"http/1.1", "h2", "h3"}
    if active_streams < 0 or stream_limit <= 0:
        return {"admit": False, "multiplexed": False}
    multiplexed = protocol in {"h2", "h3"}
    effective_limit = stream_limit if multiplexed else min(1, stream_limit)
    return {"admit": active_streams < effective_limit, "multiplexed": multiplexed}

